import{_ as e,o as d,c as o,ag as n}from"./chunks/framework.HG0H2VLS.js";const h=JSON.parse('{"title":"Menu — Figma Notes (Control Centre)","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/cc/patterns/Menu/Menu.figma-notes.md","filePath":"public/demos/src/cc/patterns/Menu/Menu.figma-notes.md"}'),r={name:"public/demos/src/cc/patterns/Menu/Menu.figma-notes.md"};function c(a,t,i,s,l,u){return d(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="menu-—-figma-notes-control-centre" tabindex="-1">Menu — Figma Notes (Control Centre) <a class="header-anchor" href="#menu-—-figma-notes-control-centre" aria-label="Permalink to &quot;Menu — Figma Notes (Control Centre)&quot;">​</a></h1><p><strong>Figma:</strong> <a href="https://www.figma.com/design/ETKqleZdpertwFEo40YB5n/Affino-CC-Hybrid--Design-System?node-id=4061-16921" target="_blank" rel="noreferrer"><code>node 4061:16921</code></a> — &quot;Menu&quot; pattern set, CC Hybrid file. <strong>Tier:</strong> Pattern <strong>Files:</strong> <code>Menu.css</code>, <code>Menu.html</code>, <code>Menu.figma.ts</code>, <code>Menu.figma-notes.md</code><strong>Composes:</strong> the <code>MainMenuItem</code> component.</p><h2 id="variant-matrix-8-variants-verified-per-variant" tabindex="-1">Variant matrix (8 variants, verified per-variant) <a class="header-anchor" href="#variant-matrix-8-variants-verified-per-variant" aria-label="Permalink to &quot;Variant matrix (8 variants, verified per-variant)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>State</th><th>Node</th><th>Search?</th><th>Layout</th></tr></thead><tbody><tr><td>Control</td><td>Default</td><td>4061:17610</td><td>✓</td><td>MainMenuItem × 10 (CRM, Content, Marketing, …, Custom)</td></tr><tr><td>Control</td><td>Selected</td><td>4061:16922</td><td>✓</td><td>Same + Content expanded with 8 sub-items</td></tr><tr><td>Control</td><td>Scrolled</td><td>4061:16969</td><td>✗</td><td>No brand/search; Content expanded (5 sub-items visible)</td></tr><tr><td>Analysis</td><td>Default</td><td>4061:18194</td><td>✗</td><td>MainMenuItem × 8 (Dashboards, CRM, Content, …, System)</td></tr><tr><td>Analysis</td><td>Selected</td><td>4061:18311</td><td>✗</td><td>Same + Dashboards expanded with 5 sub-items</td></tr><tr><td>Favourites</td><td>Selected</td><td>4061:18403</td><td>✓ &quot;Search Favourites&quot;</td><td>3 trash-icon rows (Analysis Dashboard / Articles / CRM)</td></tr><tr><td>CRM</td><td>Default</td><td>4061:17731</td><td>✓ &quot;Search CRM&quot;</td><td>6 plus-icon menu buttons + Recent (5 contacts) + &quot;show more&quot;</td></tr><tr><td>CRM</td><td>Expanded</td><td>4061:18053</td><td>✓ &quot;Search CRM&quot;</td><td>Same + 3 more recents (8 total) + &quot;show less&quot;</td></tr></tbody></table><p>Type controls layout; State controls which item is selected/expanded and whether the search/brand chrome is visible.</p><h2 id="css-classes" tabindex="-1">CSS classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th></tr></thead><tbody><tr><td>Panel container</td><td><code>&lt;nav class=&quot;cc-menu&quot;&gt;</code> (<code>align-items: center</code> so children centre horizontally)</td></tr><tr><td>CRM layout modifier</td><td><code>.cc-menu--crm</code> (10px gap + padding instead of 12)</td></tr><tr><td>Affino wordmark strip</td><td><code>.cc-menu__brand</code> — 167 × 72 cell, centred horizontally by the panel&#39;s <code>align-items: center</code>. CSS <code>mask</code> paints the wordmark in <code>--cc-mainmenu-icon</code>, vertically centred inside the taller 72 slot.</td></tr><tr><td>Search input</td><td><code>&lt;label class=&quot;cc-menu__search&quot;&gt;</code> containing search icon + input</td></tr><tr><td>Items list</td><td><code>&lt;ul class=&quot;cc-menu__items&quot;&gt;</code></td></tr><tr><td>Submenu list (under an expanded item)</td><td><code>&lt;ul class=&quot;cc-menu__submenu&quot;&gt;</code></td></tr><tr><td>Submenu item</td><td><code>&lt;li class=&quot;cc-menu__submenu-item&quot;&gt;</code></td></tr><tr><td>Submenu item trailing icon</td><td><code>&lt;button class=&quot;cc-menu__submenu-item__action&quot;&gt;</code> (e.g. pin, trash)</td></tr><tr><td>CRM type — groups wrapper</td><td><code>.cc-menu__crm-groups</code></td></tr><tr><td>CRM type — group</td><td><code>.cc-menu__crm-group</code></td></tr><tr><td>CRM type — menu button (text + plus icon)</td><td><code>&lt;button class=&quot;cc-menu__crm-btn&quot;&gt;</code></td></tr><tr><td>CRM type — Recent heading</td><td><code>&lt;p class=&quot;cc-menu__recent-heading&quot;&gt;</code> (bold + white)</td></tr><tr><td>CRM type — Recent item</td><td><code>&lt;button class=&quot;cc-menu__recent-item&quot;&gt;</code> (label + right-pointing chevron)</td></tr><tr><td>CRM type — show more/less toggle</td><td><code>&lt;button class=&quot;cc-menu__show-toggle&quot;&gt;</code></td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Panel bg</td><td><code>--cc-mainmenu-secondary-bg</code></td></tr><tr><td>Panel width</td><td><code>--ai-size-5</code> (280)</td></tr><tr><td>Panel padding</td><td><code>--ai-spacing-4</code> (12 — Control/Analysis/Favourites); <code>10px</code> (CRM only)</td></tr><tr><td>Panel gap</td><td><code>--ai-spacing-3</code> (8 — Control/Analysis/Favourites); <code>10px</code> (CRM only)</td></tr><tr><td>Items gap</td><td><code>--ai-spacing-1</code> (4)</td></tr><tr><td>Search field bg</td><td><code>--ai-surface-elevated-1</code> (user override; was <code>--ai-surface-primary</code>)</td></tr><tr><td>Search field border</td><td><code>--ai-border-secondary</code>; <code>:focus-within</code> → <code>--ai-border-brand</code> + double box-shadow ring (<code>--ai-surface-brand-soft</code>), mirroring the Input component (the nested input has <code>outline:none</code>, so the wrapper carries the focus indicator)</td></tr><tr><td>Search field height / padding</td><td>40 / <code>--ai-spacing-5</code> horizontal</td></tr><tr><td>Search placeholder</td><td><code>--ai-text-contrast</code></td></tr><tr><td>Search input typed</td><td><code>--ai-text-primary</code></td></tr><tr><td>Submenu padding</td><td><code>--ai-spacing-3</code> <code>--ai-spacing-4</code> (8 / 12)</td></tr><tr><td>Submenu item gap</td><td><code>--ai-spacing-2</code> (6)</td></tr><tr><td>Submenu item colour</td><td><code>--ai-text-invert-secondary</code></td></tr><tr><td>Submenu action icon (pin / trash)</td><td>rest: <code>--ai-icon-invert-secondary</code>, opacity 0 → 0.7 on row hover → 1 + <code>--cc-mainmenu-icon</code> on icon hover</td></tr><tr><td>CRM <code>crm-btn</code> width</td><td>100% (fills its <code>crm-group</code> parent)</td></tr><tr><td>CRM <code>crm-btn</code> icon size</td><td><code>--ai-icon-size-md</code> (20)</td></tr><tr><td>CRM <code>crm-btn</code> icon colour</td><td>rest: <code>--ai-icon-invert-secondary</code>, hover: <code>--cc-mainmenu-icon</code> (label hover: <code>--ai-text-invert</code>)</td></tr><tr><td>CRM Recent heading colour</td><td><code>--ai-text-invert</code> (white, bold)</td></tr><tr><td>CRM Recent item colour</td><td>rest: <code>--ai-text-invert-secondary</code>, hover: <code>--ai-text-invert</code></td></tr><tr><td>CRM Recent chevron colour</td><td>rest: <code>--ai-icon-invert-secondary</code>, hover (on row): <code>--cc-mainmenu-icon</code></td></tr><tr><td>CRM Recent chevron rotation</td><td><code>rotate(-90deg)</code> so chevron-down points right</td></tr><tr><td>CRM <code>show-toggle</code> font</td><td><code>--ai-font-fixed-xxs</code> (12)</td></tr><tr><td>CRM <code>show-toggle</code> colours</td><td>label rest: <code>--ai-text-invert-secondary</code>, hover: <code>--ai-text-invert</code>; icon rest: <code>--ai-icon-invert-secondary</code>, hover: <code>--cc-mainmenu-icon</code></td></tr></tbody></table><p><strong>Duotone rule (applies to all Types):</strong> every icon inside the Menu panel uses <code>--ai-icon-invert-secondary</code> at rest and promotes to <code>--cc-mainmenu-icon</code> on its hover/active state; every label uses <code>--ai-text-invert-secondary</code> at rest and promotes to <code>--ai-text-invert</code> on hover. This matches the MainMenuItem and Sidebar contrast convention so the navy chrome reads as a single coherent system.</p><p>The MainMenuItem rows inside <code>.cc-menu__items</code> (Control / Analysis) compose the <code>.cc-main-menu-item</code> component documented separately.</p><h2 id="notes-outstanding" tabindex="-1">Notes / Outstanding <a class="header-anchor" href="#notes-outstanding" aria-label="Permalink to &quot;Notes / Outstanding&quot;">​</a></h2><ul><li><strong>Scrolled state</strong> in v1 is just the layout: no brand / no search. Hooking a real scroll-shadow that appears when the items list actually scrolls is a follow-up (no JS yet).</li><li><strong>CRM-only tokens</strong> like the 10px gap/padding don&#39;t exist in the token system as <code>--ai-spacing-*</code> values. Hardcoded with comments per the project convention for one-off optical values inside CSS.</li><li>The Type=Analysis variant omits the search input per Figma. If the consuming app needs search there, treat it as an override.</li></ul>',13)])])}const p=e(r,[["render",c]]);export{h as __pageData,p as default};
